sp_page.css:
// RAJ - this was added for the Tasker Menu Header on each page for page switching
.navbar-nav {     float:none;     margin:0 auto;     display: block;     text-align: center; } .navbar-nav > li {     display: inline-block;     float:none; }

// -----------------------------------------------------------------------------------------------------------------------
// *** BEGIN Block ********************************
// RAJ - this block was added for bifold.  It works great in some pages, but is causing an issue with Modals in some pages.
//       This block is also causing an issue with the Template list page where it is removing the tabs on the widget
// -----------------------------------------------------------------------------------------------------------------------

//---------------------------------------------------------------------------------
//KT Wrapping Table Headers
.v5001b062d7101200b0b044580e6103eb .th-title {
  display: inline-block;
  color: $primary;
  //KT
  white-space: normal;
}

.text-nowrap {
    white-space: normal;
}

// each column has a flex-item classs
.flex-item {
  width: 50%;
  position: relative;
// NOTE: removing this margin puts the header back on the data table, but puts the 2 sides of the page right next to each other
  margin:5px;
}


.panel {
  position: absolute;
  top: 0;
  bottom: 0;
  right: 0;
  left: 0;
  margin: 0;
  overflow: hidden;
  border-radius: 0;
  // flexbox
  display: flex; 
  flex-direction: column;


  .panel-body {
    overflow: scroll;
    -webkit-overflow-scrolling: touch;
    flex-grow: 1;
    padding-top: 2px; //30px; 
  }

  .panel-heading, .panel-footer {
    flex-shrink: 0;
  }
  .panel-heading {
    height: 75px;//52px;
  }
}

// -----------------------------------------------------------------------------------------------------------------------
// *** END Block ********************************
// RAJ - this block was added for bifold.  It works great in some pages, but is causing an issue with Modals in some pages.
//       This block is also causing an issue with the Template list page where it is removing the tabs on the widget
// -----------------------------------------------------------------------------------------------------------------------

.sp-attachments-input {
  visibility: hidden;
  position: absolute;
  left: 0px;
}


.file-selector {
  float: right;
  font-size: 24px;
  margin-top: -5px;
}
